import{_ as i,o as a,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"ModLink Studio 文档总览","description":"","frontmatter":{"layout":"home","hero":{"name":"ModLink Studio","text":"面向设备接入、多模态采集与展示的文档站","tagline":"这个文档站记录的是 ModLink Studio 的接入方式、运行时结构，以及围绕这些能力展开的展示与应用组织方式","actions":[{"theme":"brand","text":"查看 SDK","link":"/sdk"},{"theme":"alt","text":"查看 Core","link":"/core"}]},"features":[{"icon":"🔌","title":"设备接入","details":"这里记录 driver 的基本契约，以及一个设备如何通过 SearchResult、StreamDescriptor 和 FrameEnvelope 接入整套平台。"},{"icon":"🧠","title":"轻量开发","details":"常见轮询设备可以直接使用 LoopDriver；遇到 callback 型或更特殊的设备时，再回到基础 Driver 即可。"},{"icon":"📡","title":"统一流模型","details":"设备一旦接入，系统内部主要围绕 stream_id、payload_type、数据 shape 和 descriptor 来协作，而不是继续依赖具体设备协议。"},{"icon":"🧩","title":"分层组织","details":"SDK 负责接入契约，Core 负责运行时与总线，UI 负责展示，App 负责最终组装与启动。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1774343036000}'),l={name:"index.md"};function d(t,e,c,n,p,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<div style="height:1.5rem;"></div><h1 id="modlink-studio-文档总览" tabindex="-1">ModLink Studio 文档总览 <a class="header-anchor" href="#modlink-studio-文档总览" aria-label="Permalink to &quot;ModLink Studio 文档总览&quot;">​</a></h1><p><code>ModLink Studio</code> 是一个面向设备接入、多模态采集与展示的项目。</p><p>我目前主要把文档写在两个方向上：</p><ul><li>如何为项目新增一个 driver</li><li>如何在已有流模型上继续做展示、录制和应用组装</li></ul><h2 id="阅读顺序-为项目新增一个-driver" tabindex="-1">阅读顺序：为项目新增一个 driver <a class="header-anchor" href="#阅读顺序-为项目新增一个-driver" aria-label="Permalink to &quot;阅读顺序：为项目新增一个 driver&quot;">​</a></h2><p>如果目标是为项目新增加一个 driver，我会建议按下面这个顺序阅读：</p><ol><li><a href="/sdk">SDK 开发者指南</a></li><li><a href="/core">Core 模块架构</a></li><li><a href="/api">API 快速索引</a></li><li><a href="/app">App 组合根</a></li></ol><p>这条顺序的原因很简单：</p><ul><li><code>SDK</code> 先定义接入契约</li><li><code>Core</code> 再说明这些契约在运行时里如何被调用和消费</li><li><code>API</code> 方便回头查具体类型和方法</li><li><code>App</code> 负责补上插件挂载和最终启动方式</li></ul><h2 id="这套文档主要覆盖的两个层面" tabindex="-1">这套文档主要覆盖的两个层面 <a class="header-anchor" href="#这套文档主要覆盖的两个层面" aria-label="Permalink to &quot;这套文档主要覆盖的两个层面&quot;">​</a></h2><h3 id="_1-如何编写-driver" tabindex="-1">1. 如何编写 driver <a class="header-anchor" href="#_1-如何编写-driver" aria-label="Permalink to &quot;1. 如何编写 driver&quot;">​</a></h3><p>这里主要记录：</p><ul><li>什么时候直接继承 <code>Driver</code></li><li>什么时候优先使用 <code>LoopDriver</code></li><li><code>SearchResult</code>、<code>StreamDescriptor</code>、<code>FrameEnvelope</code> 分别承担什么职责</li><li>一个插件怎样通过 <code>uv run --with ...</code> 挂到当前运行环境里</li></ul><h3 id="_2-如何使用这个项目" tabindex="-1">2. 如何使用这个项目 <a class="header-anchor" href="#_2-如何使用这个项目" aria-label="Permalink to &quot;2. 如何使用这个项目&quot;">​</a></h3><p>这里主要记录：</p><ul><li><code>Core</code>、<code>UI</code> 和 <code>App</code> 各自负责什么</li><li>上层模块应该依赖哪些稳定约定，而不是依赖设备细节</li><li>一个已经接入的设备怎样被展示、录制和组装进具体应用</li></ul><h2 id="常用入口" tabindex="-1">常用入口 <a class="header-anchor" href="#常用入口" aria-label="Permalink to &quot;常用入口&quot;">​</a></h2><ul><li><a href="/sdk">SDK 页面</a>：driver 契约、LoopDriver、共享数据模型</li><li><a href="/core">Core 页面</a>：driver portal、engine、stream bus、录制链路</li><li><a href="/ui">UI 页面</a>：展示层应该依赖的稳定边界</li><li><a href="/app">App 页面</a>：插件发现、应用入口和启动方式</li><li><a href="/api">API 页面</a>：pdoc 自动文档入口</li></ul>',19)])])}const m=i(l,[["render",d]]);export{u as __pageData,m as default};
